// 1. setTimeout: Tapşırığı müəyyən gecikmə ilə yerinə yetirir
function loadGameLevel(level, callback) {
  console.log(`Səviyyə ${level} yüklənir...`);
  setTimeout(() => {
    console.log(`Səviyyə ${level} yükləndi!`);
    callback();
  }, 2000);
}

loadGameLevel(1, () => {
  console.log("Oyunçu səviyyəyə daxil oldu!");
});
// nəticə:
// Səviyyə 1 yüklənir...
// (2 saniyə sonra) Səviyyə 1 yükləndi!
// Oyunçu səviyyəyə daxil oldu!

// 2. Promise: Gələcək nəticəni təmsil edir
function fetchPlayerData(playerId) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve({ id: playerId, score: 1000 });
      } else {
        reject("Oyunçu məlumatları yüklənmədi!");
      }
    }, 1500);
  });
}

fetchPlayerData(123)
  .then(data => console.log(`Oyunçu skoru: ${data.score}`))
  .catch(error => console.log(`Səhv: ${error}`));
// nəticə (ehtimala görə):
// Oyunçu skoru: 1000
// və ya: Səhv: Oyunçu məlumatları yüklənmədi!

// 3. async/await: Promise-ləri daha oxunaqlı idarə edir
async function startGame(playerId) {
  try {
    console.log("Oyun başlayır...");
    let data = await fetchPlayerData(playerId);
    console.log(`Oyunçu ${playerId} hazırdır, skor: ${data.score}`);
  } catch (error) {
    console.log(`Səhv: ${error}`);
  }
}

startGame(123);
// nəticə:
// Oyun başlayır...
// (1.5 saniyə sonra) Oyunçu 123 hazırdır, skor: 1000

// 4. fetch: Serverdən məlumat almaq
async function getGameLeaderboard() {
  try {
    let response = await fetch("https://api.example.com/leaderboard");
    let data = await response.json();
    console.log("Liderlər: ", data);
  } catch (error) {
    console.log("Server səhvi: ", error);
  }
}

getGameLeaderboard();
// nəticə: API-dən asılı olaraq liderlər siyahısı və ya səhv

// Callback Hell nümunəsi
function loadLevel(level, callback) {
  setTimeout(() => {
    console.log(`Səviyyə ${level} yükləndi`);
    callback();
  }, 1000);
}

loadLevel(1, () => {
  loadLevel(2, () => {
    loadLevel(3, () => {
      console.log("Bütün səviyyələr yükləndi!");
    });
  });
});

// Eyni tapşırıq async/await ilə
async function loadAllLevels() {
  try {
    await fetchPlayerData(1);
    console.log("Səviyyə 1 yükləndi");
    await fetchPlayerData(2);
    console.log("Səviyyə 2 yükləndi");
    await fetchPlayerData(3);
    console.log("Bütün səviyyələr yükləndi!");
  } catch (error) {
    console.log("Səhv: ", error);
  }
}

loadAllLevels();

