// 1. setTimeout: Runs a task after a delay
function loadGameLevel(level, callback) {
  console.log(`Level ${level} loading...`);
  setTimeout(() => {
    console.log(`Level ${level} loaded!`);
    callback();
  }, 2000);
}

loadGameLevel(1, () => {
  console.log("Player entered the level!");
});
// Output:
// Level 1 loading...
// (2 seconds later) Level 1 loaded!
// Player entered the level!

// 2. Promise: Represents a future result
function fetchPlayerData(playerId) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve({ id: playerId, score: 1000 });
      } else {
        reject("Player data failed to load!");
      }
    }, 1500);
  });
}

fetchPlayerData(123)
  .then(data => console.log(`Player score: ${data.score}`))
  .catch(error => console.log(`Error: ${error}`));
// Output (depending on chance):
// Player score: 1000
// or: Error: Player data failed to load!

// 3. async/await: Makes Promises more readable
async function startGame(playerId) {
  try {
    console.log("Game starting...");
    let data = await fetchPlayerData(playerId);
    console.log(`Player ${playerId} ready, score: ${data.score}`);
  } catch (error) {
    console.log(`Error: ${error}`);
  }
}

startGame(123);
// Output:
// Game starting...
// (1.5 seconds later) Player 123 ready, score: 1000

// 4. fetch: Fetches data from a server
async function getGameLeaderboard() {
  try {
    let response = await fetch("https://api.example.com/leaderboard");
    let data = await response.json();
    console.log("Leaderboard: ", data);
  } catch (error) {
    console.log("Server error: ", error);
  }
}

getGameLeaderboard();
// Output: Leaderboard data or error, depending on API

// Callback Hell example
function loadLevel(level, callback) {
  setTimeout(() => {
    console.log(`Level ${level} loaded`);
    callback();
  }, 1000);
}

loadLevel(1, () => {
  loadLevel(2, () => {
    loadLevel(3, () => {
      console.log("All levels loaded!");
    });
  });
});

// Same task with async/await
async function loadAllLevels() {
  try {
    await fetchPlayerData(1);
    console.log("Level 1 loaded");
    await fetchPlayerData(2);
    console.log("Level 2 loaded");
    await fetchPlayerData(3);
    console.log("All levels loaded!");
  } catch (error) {
    console.log("Error: ", error);
  }
}

loadAllLevels();

