// 1. setTimeout: Выполняет задачу с задержкой
function loadGameLevel(level, callback) {
  console.log(`Уровень ${level} загружается...`);
  setTimeout(() => {
    console.log(`Уровень ${level} загружен!`);
    callback();
  }, 2000);
}

loadGameLevel(1, () => {
  console.log("Игрок вошёл на уровень!");
});
// Вывод:
// Уровень 1 загружается...
// (2 секунды спустя) Уровень 1 загружен!
// Игрок вошёл на уровень!

// 2. Promise: Представляет будущий результат
function fetchPlayerData(playerId) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve({ id: playerId, score: 1000 });
      } else {
        reject("Данные игрока не загружены!");
      }
    }, 1500);
  });
}

fetchPlayerData(123)
  .then(data => console.log(`Очки игрока: ${data.score}`))
  .catch(error => console.log(`Ошибка: ${error}`));
// Вывод (в зависимости от шанса):
// Очки игрока: 1000
// или: Ошибка: Данные игрока не загружены!

// 3. async/await: Делает Promises более читаемыми
async function startGame(playerId) {
  try {
    console.log("Игра начинается...");
    let data = await fetchPlayerData(playerId);
    console.log(`Игрок ${playerId} готов, очки: ${data.score}`);
  } catch (error) {
    console.log(`Ошибка: ${error}`);
  }
}

startGame(123);
// Вывод:
// Игра начинается...
// (1.5 секунды спустя) Игрок 123 готов, очки: 1000

// 4. fetch: Получает данные с сервера
async function getGameLeaderboard() {
  try {
    let response = await fetch("https://api.example.com/leaderboard");
    let data = await response.json();
    console.log("Таблица лидеров: ", data);
  } catch (error) {
    console.log("Ошибка сервера: ", error);
  }
}

getGameLeaderboard();
// Вывод: Данные таблицы лидеров или ошибка, в зависимости от API

