function loadLevel(level, callback) {
  setTimeout(() => {
    console.log(`Уровень ${level} загружен`);
    callback();
  }, 1000);
}

loadLevel(1, () => {
  loadLevel(2, () => {
    loadLevel(3, () => {
      console.log("Все уровни загружены!");
